const APPEND_LINKS = true;

// --- Get label dates ---
let dateLabels = "";
try {
    const formatLabels = $('Filter Labels Starting With v2')?.first()?.json;
    const oldestDate = formatLabels?.oldestLabelDate;
    const newestDate = formatLabels?.newestLabelDate;
    dateLabels = (oldestDate && newestDate) ? `[${oldestDate} → ${newestDate}]` : "";
} catch (error) {
    dateLabels = "";
}

// --- Get version labels ---
let versionsLabels = [];
try {
    const versionsLabelNodeOutput = $('Parse Linear Version Labels').first().json.versions_labels;
    versionsLabels = typeof versionsLabelNodeOutput === 'string'
        ? JSON.parse(versionsLabelNodeOutput)
        : Array.isArray(versionsLabelNodeOutput)
            ? versionsLabelNodeOutput
            : [];
} catch (error) {
    versionsLabels = [];
}

// --- Get custom labels to include ---
let includeLabels = [];
try {
    const includeLabelNodeOutput = $('Parse Linear Version Labels').first().json.custom_labels;
    includeLabels = typeof includeLabelNodeOutput === 'string'
        ? JSON.parse(includeLabelNodeOutput)
        : Array.isArray(includeLabelNodeOutput)
            ? includeLabelNodeOutput
            : [];
} catch (error) {
    includeLabels = [];
}

// --- Initialize stats and grouping ---
let totalTickets = 0;
let ticketsWithZendesk = 0;
let ticketsWithCustomLabels = 0;
const issuesByTeam = {};

// --- Slack link helper ---
function extractFirstSlackLink(attachments) {
    if (!attachments || !Array.isArray(attachments.nodes)) return null;
    for (const att of attachments.nodes) {
        if (att.url?.includes("your-company.slack.com/archives/")) {
            return att.url;
        }
    }
    return null;
}

// --- Process each issue ---
const data = $input.first().json.data; // Get the original data
const items = data.issues.nodes;
for (const item of items) {
    const issue = item;
    totalTickets++;

    const teamName = issue.team?.name || 'Unknown Team';
    if (!issuesByTeam[teamName]) {
        issuesByTeam[teamName] = [];
    }
    issuesByTeam[teamName].push(issue);

    const zendeskAttachment = (issue.attachments?.nodes || []).find(att => att.url?.includes("your-company.zendesk.com"));
    if (zendeskAttachment) {
        ticketsWithZendesk++;
    }

    const issueLabels = issue.labels?.nodes || [];
    if (includeLabels.length > 0 && issueLabels.some(l => includeLabels.includes(l.name))) {
        ticketsWithCustomLabels++;
    }
}

// --- Build Markdown output ---
let fullMarkdownContent = `## 📊 Ticket Summary\n`;
fullMarkdownContent += `List of customer-facing improvements and bug fixes.\n`;
fullMarkdownContent += `- Release labels: **${versionsLabels.join(', ')}** ${dateLabels}\n`;
fullMarkdownContent += `- Total tickets: **${totalTickets}**\n`;
fullMarkdownContent += `- Tickets with Zendesk: **${ticketsWithZendesk}**\n`;
fullMarkdownContent += `- Tickets with custom labels (${includeLabels.join(', ')}): **${ticketsWithCustomLabels}**\n`;

fullMarkdownContent += `\n## 🗂️ Tickets\n`;

const sortedTeams = Object.keys(issuesByTeam).sort();
for (const team of sortedTeams) {
    const teamIssues = issuesByTeam[team];
    teamIssues.sort((a, b) => (a.identifier && b.identifier) ? a.identifier.localeCompare(b.identifier) : 0);

    fullMarkdownContent += `\n### ${team}\n`;

    for (const issue of teamIssues) {
        const labels = (issue.labels?.nodes || []).map(l => l.name).join(", ");

        const linearLink = APPEND_LINKS
            ? `[${issue.identifier}](https://linear.app/YOUR_WORKSPACE/issue/${issue.identifier})`
            : issue.identifier;

        // --- Zendesk link (per issue) ---
        let zendeskLink = "";
        const zAttachment = (issue.attachments?.nodes || []).find(att => att.url?.includes("your-company.zendesk.com"));
        if (zAttachment) {
            const ticketMatch = zAttachment.url.match(/tickets\/(\d+)/);
            const ticketId = ticketMatch?.[1];
            if (ticketId) {
                zendeskLink = APPEND_LINKS
                    ? `(Zendesk [#${ticketId}](${zAttachment.url}))`
                    : `(Zendesk #${ticketId})`;
            }
        }

        // --- Slack link ---
        const slackLinkUrl = extractFirstSlackLink(issue.attachments);
        const slackLink = slackLinkUrl
            ? APPEND_LINKS
                ? `(Slack [link](${slackLinkUrl}))`
                : `(Slack link)`
            : "";

        fullMarkdownContent += `- [ ] ${linearLink} - ${issue.title} - ${labels} ${zendeskLink} ${slackLink}`.trim() + `\n`;
    }
}

return [{ json: { markdown: fullMarkdownContent } }];

