// Parse version_labels
const rawVersionLabels = $json['versions_labels'];
const versionLabels = typeof rawVersionLabels === 'string' ? JSON.parse(rawVersionLabels) : rawVersionLabels;

// Parse custom_labels
const rawCustomLabels = $json['custom_labels'];
const customLabels = typeof rawCustomLabels === 'string' ? JSON.parse(rawCustomLabels) : rawCustomLabels;

const versions_labels_expanded = [];
const custom_labels_expanded = []; // NEW: Array to hold expanded custom labels

// Helper function for expanding version ranges
function expandVersionRange(label, targetArray) {
    const match = /^v2\.(\d+)-v2\.(\d+)$/.exec(label);
    if (match) {
        const start = parseInt(match[1], 10);
        const end = parseInt(match[2], 10);
        for (let i = start; i <= end; i++) {
            targetArray.push(`v2.${i}`);
        }
    } else {
        targetArray.push(label); // If not a range, push the label as is
    }
}

// Expand versions_labels
for (const label of versionLabels) {
    expandVersionRange(label, versions_labels_expanded);
}

// NEW: Expand custom_labels
for (const label of customLabels) {
    expandVersionRange(label, custom_labels_expanded);
}

// Return both expanded arrays in the output JSON
return [{ json: {
    ...$json, // Keep original input data
    versions_labels_expanded, // Expanded version labels
    custom_labels_expanded    // NEW: Expanded custom labels
} }];
